                    </div>
                    <div className="flex flex-col items-end gap-2">
                      <StatusBadge status={doc.Status} />
                      <button 
                        onClick={() => alert(`Reminder sent for: ${doc.Document}`)}
                        className="px-4 py-2 rounded-lg text-sm font-medium"
                        style={{ background: colors.bg.input, color: colors.text.primary, border: `1px solid ${colors.bg.border}` }}
                      >
                        Send Reminder
                      </button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Findings */}
        {activeTab === 'findings' && (
          <div className="p-6 overflow-auto h-full">
            <div className="flex items-center justify-between mb-6">
              <div>
                <h2 className="text-xl font-bold" style={{ color: colors.text.primary }}>Audit Findings</h2>
                <p style={{ color: colors.text.secondary }}>
                  {findings.length} findings ({findings.filter(f => f['AI Draft'] === '__YES__').length} AI-drafted)
                </p>
              </div>
              <button 
                onClick={() => alert('Generate AI finding (coming soon)')}
                className="flex items-center gap-2 px-4 py-2.5 rounded-lg font-medium text-sm transition-all hover:scale-105"
                style={{ background: colors.gradient.primary, color: colors.text.inverse }}
              >
                <span className="w-4 h-4"><Icons.Sparkle /></span>
                Generate Finding
              </button>
            </div>
            <div className="grid gap-4">
              {findings.map(finding => (
                <FindingCard key={finding['Finding ID']} finding={finding} onAction={handleFindingAction} />
              ))}
            </div>
          </div>
        )}
      </main>

      {/* Footer */}
      <footer className="px-6 py-3 flex items-center justify-between text-xs" style={{ background: colors.bg.card, borderTop: `1px solid ${colors.bg.border}` }}>
        <div className="flex items-center gap-6" style={{ color: colors.text.muted }}>
          <span><strong style={{ color: colors.accent.success }}>{controls.filter(c => c.Status === 'Done').length}/{controls.length}</strong> Controls</span>
          <span><strong style={{ color: colors.accent.warning }}>{documents.filter(d => d.Status !== 'Done').length}</strong> PBCs Pending</span>
          <span><strong style={{ color: colors.accent.danger }}>{findings.filter(f => f['Risk Rating'] === 'Critical').length}</strong> Critical Findings</span>
        </div>
        <div className="flex items-center gap-2" style={{ color: colors.text.muted }}>
          <span className="w-4 h-4"><Icons.Database /></span>
          <span>Synced with Notion • Last updated: {new Date().toLocaleTimeString()}</span>
        </div>
      </footer>
    </div>
  );
}
